// src/graph-runtime/dotgraph/camera/controls/usePixelOffsets.ts
import { useEffect, useRef } from 'react';
import { useFrame } from '../../../r3f';
import type { RefObject } from 'react';
import type { Camera, Group } from '../../../three';
import { pauseSpriteTextureQueue, resumeSpriteTextureQueue } from '../../../sprites/entry';

interface PerspectiveCameraLike extends Camera {
  aspect: number;
  fov: number;
}

interface UsePixelOffsetsParams {
  groupRef: RefObject<Group | null>;
  camera: Camera;
  domElement: HTMLElement;
  radius: number;
  xOffset: number;
  yOffset: number;
  xOffsetPx: number;
  yOffsetPx: number;
}

const isPerspectiveCameraLike = (camera: Camera): camera is PerspectiveCameraLike =>
  "aspect" in camera &&
  "fov" in camera &&
  typeof camera.aspect === "number" &&
  typeof camera.fov === "number";

export default function usePixelOffsets({
  groupRef,
  camera,
  domElement,
  radius,
  xOffset,
  yOffset,
  xOffsetPx,
  yOffsetPx,
}: UsePixelOffsetsParams) {
  const desiredPxRef = useRef({ x: xOffsetPx, y: yOffsetPx });
  const animPxRef = useRef({ x: xOffsetPx, y: yOffsetPx });
  const queuePausedRef = useRef(false);

  useEffect(() => {
    desiredPxRef.current = { x: xOffsetPx, y: yOffsetPx };
  }, [xOffsetPx, yOffsetPx]);

  // Resume queue on unmount in case we paused and never settled
  useEffect(() => {
    return () => {
      if (queuePausedRef.current) {
        resumeSpriteTextureQueue();
        queuePausedRef.current = false;
      }
    };
  }, []);

  useFrame((_, delta) => {
    const g = groupRef.current;
    if (!g) return;

    const targetPx = desiredPxRef.current;
    const anim = animPxRef.current;

    const dx = targetPx.x - anim.x;
    const dy = targetPx.y - anim.y;
    const moving = dx * dx + dy * dy > 0.25; // >0.5px total distance

    if (moving && !queuePausedRef.current) {
      pauseSpriteTextureQueue();
      queuePausedRef.current = true;
    } else if (!moving && queuePausedRef.current) {
      resumeSpriteTextureQueue();
      queuePausedRef.current = false;
    }

    const alpha = 1 - Math.exp(-((delta > 0 ? delta : 0.016) / 0.25));
    anim.x += dx * alpha;
    anim.y += dy * alpha;

    const rect = domElement.getBoundingClientRect();
    const W = rect.width || domElement.clientWidth || window.innerWidth || 1;
    const H = rect.height || domElement.clientHeight || window.innerHeight || 1;

    const aspect = isPerspectiveCameraLike(camera) ? camera.aspect : W / H;
    const fov = isPerspectiveCameraLike(camera) ? camera.fov : 50;
    const fovRad = (fov * Math.PI) / 180;

    const worldPerPxY = (2 * Math.tan(fovRad / 2) * radius) / H;
    const worldPerPxX = worldPerPxY * aspect;

    const offX = xOffset + anim.x * worldPerPxX;
    const offY = yOffset + -anim.y * worldPerPxY;

    g.position.set(offX, offY, 0);
  });
}
